// Build enriched deal data for Claude analysis
const leads = $('Get Active Leads').all().map(l => l.json);
const interactions = $('Get All Interactions').all().map(i => i.json);
const meetings = $('Get All Meetings').all().map(m => m.json);

const now = new Date();

const enrichedDeals = leads.map(lead => {
  const leadInteractions = interactions.filter(i => i.lead_id === (lead.id || lead.lead_id));
  const leadMeetings = meetings.filter(m => m.lead_id === (lead.id || lead.lead_id));
  const lastInteraction = leadInteractions[0];
  const lastMeeting = leadMeetings[0];

  const daysSinceContact = lastInteraction
    ? Math.floor((now - new Date(lastInteraction.sent_at)) / (1000 * 60 * 60 * 24))
    : 999;
  const daysSinceMeeting = lastMeeting
    ? Math.floor((now - new Date(lastMeeting.meeting_date)) / (1000 * 60 * 60 * 24))
    : 999;
  const daysInPipeline = lead.created_at
    ? Math.floor((now - new Date(lead.created_at)) / (1000 * 60 * 60 * 24))
    : 0;

  return {
    company_name: lead.company_name,
    lead_id: lead.id || lead.lead_id,
    lead_score: lead.lead_score || 0,
    last_contact_at: lastInteraction?.sent_at || null,
    last_meeting_date: lastMeeting?.meeting_date || null,
    last_deal_signal: lastMeeting?.deal_signal || null,
    contact_attempts: leadInteractions.filter(i => i.direction === 'outbound').length,
    days_since_contact: daysSinceContact,
    days_since_meeting: daysSinceMeeting,
    days_in_pipeline: daysInPipeline,
    pipeline_stage: lead.status || lead.pipeline_stage || 'unknown',
    assigned_to: lead.owner_id || lead.assigned_to,
    has_replied: leadInteractions.some(i => i.direction === 'inbound')
  };
});

// Process in batches of 15 to avoid token limits
const batchSize = 15;
const batches = [];
for (let i = 0; i < enrichedDeals.length; i += batchSize) {
  batches.push(enrichedDeals.slice(i, i + batchSize));
}

return batches.map(batch => ({ json: { deals: batch } }));

// Parse Claude response and filter actionable alerts
const raw = $('Claude — Analyze Deal Health').first().json;
let alerts;
try {
  const text = typeof raw === 'string' ? raw : (raw.text || raw.content || JSON.stringify(raw));
  const jsonMatch = text.match(/\[[\s\S]*\]/);
  alerts = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch (e) {
  alerts = [];
}

// Filter out healthy deals — only return actionable alerts
const actionableAlerts = alerts.filter(a => a.alert_type !== 'healthy');

return actionableAlerts.map(alert => ({ json: alert }));

// Build Slack alert messages for urgent items
const alert = $json;

const emoji = {
  close_now: '🎯',
  at_risk: '⚠️',
  ghost: '👻',
  nurture: '🌱',
  disqualify: '❌'
};

const isUrgent = ['close_now', 'at_risk', 'ghost'].includes(alert.alert_type) &&
  ['critical', 'high'].includes(alert.urgency);

if (!isUrgent) return [];

const message = `${emoji[alert.alert_type] || '⚪'} *${(alert.alert_type || '').toUpperCase().replace('_', ' ')}: ${alert.company_name}*\n_${alert.reason}_\n\n*O que fazer:* ${alert.recommendation}\n${alert.suggested_message_angle ? `*Ângulo sugerido:* ${alert.suggested_message_angle}` : ''}`;

return [{ json: { message } }];
